function isMercadoPagoReturnReferrer(referrer = document.referrer) {
    const normalizedReferrer = String(referrer || '').toLowerCase()

    if (!normalizedReferrer) {
        return false
    }

    return normalizedReferrer.includes('mercadopago')
        || normalizedReferrer.includes('/payment/success')
        || normalizedReferrer.includes('/payment/failure')
        || normalizedReferrer.includes('/pagoaprobado')
        || normalizedReferrer.includes('/pagorechazado')
}

function hasPendingMercadoPagoReturnReset() {
    try {
        return sessionStorage.getItem(mercadoPagoReturnSessionKey) === '1'
    } catch (error) {
        return false
    }
}

function setPendingMercadoPagoReturnReset(pending = true) {
    try {
        if (pending) {
            sessionStorage.setItem(mercadoPagoReturnSessionKey, '1')
            return
        }

        sessionStorage.removeItem(mercadoPagoReturnSessionKey)
    } catch (error) {
        // ignore storage errors
    }
}

function shouldResetBookingStateAfterMercadoPagoReturn() {
    return hasPendingMercadoPagoReturnReset() || isMercadoPagoReturnReferrer()
}

function forceHideModalState(modalElement, modalInstance = null) {
    if (!modalElement) {
        return
    }

    modalInstance?.hide()
    bootstrap.Modal.getInstance(modalElement)?.hide()

    modalElement.classList.remove('show')
    modalElement.setAttribute('aria-hidden', 'true')
    modalElement.style.removeProperty('display')
    modalElement.removeAttribute('aria-modal')
    modalElement.removeAttribute('role')
}

function resetBookingStateAfterMercadoPagoReturn() {
    mercadoPagoCheckoutRequested = false
    setPendingMercadoPagoReturnReset(false)
    setAcceptedTermsInSession(false)

    preferencesIds = {}
    pendingMpContext = null
    publicBookingPrepared = false
    skipCancelOnHide = false

    data.preferenceIdParcial = null
    data.preferenceIdTotal = null
    data.pendingBookingId = null
    data.pagoTotal = false
    data.partialByEntries = 0
    data.entriesToPay = null
    data.paidEntries = null

    if (pendingMpCleanupTimer) {
        clearTimeout(pendingMpCleanupTimer)
        pendingMpCleanupTimer = null
    }

    if (pagoTotal) {
        pagoTotal.checked = false
    }

    if (payByEntriesToggle) {
        payByEntriesToggle.checked = false
    }

    if (payByEntriesInput) {
        payByEntriesInput.value = ''
    }

    updatePayByEntriesControls()

    const termsAccepted = document.getElementById('termsAccepted')
    if (termsAccepted) {
        termsAccepted.checked = false
    }

    termsSections.forEach((section) => {
        const checkbox = section.querySelector('.term-check')
        if (checkbox) {
            checkbox.checked = false
        }
    })

    termsFinalConfirmationVisible = false
    currentTermsStepIndex = 0

    if (confirmRulesButton) {
        confirmRulesButton.disabled = true
        confirmRulesButton.classList.add('d-none')
    }

    forceHideModalState(modalSpinner?._element || document.getElementById('modalSpinner'), modalSpinner)
    forceHideModalState(modalIngresarPagoElement, modalIngresarPago)
    forceHideModalState(modalConfirmarReserva?._element || document.getElementById('modalConfirmarReserva'), modalConfirmarReserva)

    document.querySelectorAll('.modal-backdrop').forEach((backdrop) => backdrop.remove())
    document.body.classList.remove('modal-open')
    document.body.style.removeProperty('overflow')
    document.body.style.removeProperty('padding-right')

    resetMercadoPagoButtons()
    renderCurrentTermsStep()
    updateTermsNextStep()
}

