function getAvailabilitySlotsForDate(date) {
    const normalizedDate = normalizeAvailabilityDate(date || fechaInput?.value || '')

    if (!normalizedDate) {
        return []
    }

    const availabilityData = Array.isArray(availables?.availability) ? availables.availability : []
    const selectedDay = availabilityData.find((day) => normalizeAvailabilityDate(day?.date) === normalizedDate)

    if (!selectedDay || !Array.isArray(selectedDay.available_slots)) {
        return []
    }

    return selectedDay.available_slots
        .filter((slot) => typeof slot === 'string' && slot.includes(' a '))
        .map((slot) => {
            const [start, end] = slot.split(' a ')
            return {
                start: (start || '').trim(),
                end: (end || '').trim()
            }
        })
        .filter((slot) => slot.start && slot.end)
}

function getAllowedStartTimesForDate(date, preferredStart = '') {
    const allowedStarts = new Set(getAvailabilitySlotsForDate(date).map((slot) => slot.start))

    if (preferredStart) {
        allowedStarts.add(preferredStart)
    }

    return Array.from(allowedStarts)
}

function getAllowedEndTimesForDate(date, startTime, preferredEnd = '') {
    const allowedEnds = new Set(
        getAvailabilitySlotsForDate(date)
            .filter((slot) => slot.start === startTime)
            .map((slot) => slot.end)
    )

    if (preferredEnd) {
        allowedEnds.add(preferredEnd)
    }

    return Array.from(allowedEnds)
}

function setBookingSelectOptionVisibility(option, isVisible) {
    if (!option) {
        return
    }

    option.hidden = !isVisible
    option.disabled = !isVisible
}

function syncBookingTimeSelects({
    date = selectedAvailabilityDate || fechaInput?.value || '',
    preferredStart = '',
    preferredEnd = '',
    keepCurrentSelection = false,
    autoSelectEnd = false
} = {}) {
    const normalizedDate = normalizeAvailabilityDate(date)
    const hasSelectedDate = Boolean(normalizedDate)
    const allowedStarts = getAllowedStartTimesForDate(normalizedDate, preferredStart)
    const shouldFilterStarts = hasSelectedDate

    for (let i = 0; i < horarioDesde.options.length; i++) {
        const option = horarioDesde.options[i]
        const isPlaceholder = i === 0 || option.value === ''
        const isVisible = isPlaceholder || !shouldFilterStarts || allowedStarts.includes(option.value)
        setBookingSelectOptionVisibility(option, isVisible)
    }

    horarioDesde.disabled = false

    let nextStart = preferredStart || (keepCurrentSelection ? horarioDesde.value : '')

    if (shouldFilterStarts && nextStart && !allowedStarts.includes(nextStart)) {
        nextStart = ''
    }

    horarioDesde.value = nextStart

    const allowedEnds = nextStart
        ? getAllowedEndTimesForDate(normalizedDate, nextStart, preferredEnd)
        : []

    for (let i = 0; i < horarioHasta.options.length; i++) {
        const option = horarioHasta.options[i]
        const isPlaceholder = i === 0 || option.value === ''
        const isVisible = isPlaceholder || (Boolean(nextStart) && allowedEnds.includes(option.value))
        setBookingSelectOptionVisibility(option, isVisible)
    }

    let nextEnd = preferredEnd || (keepCurrentSelection ? horarioHasta.value : '')

    if (nextEnd && !allowedEnds.includes(nextEnd)) {
        nextEnd = ''
    }

    if (!nextEnd && autoSelectEnd && allowedEnds.length > 0) {
        nextEnd = allowedEnds[0]
    }

    horarioHasta.value = nextEnd
    horarioHasta.disabled = !nextStart || allowedEnds.length === 0

    if (!nextStart) {
        horarioHasta.value = ''
        selectCancha.selectedIndex = 0
    }

    return {
        date: normalizedDate,
        start: nextStart,
        end: nextEnd,
        hasSlots: allowedStarts.length > 0
    }
}

function syncSelectedAvailabilitySlotFromTimeSelects() {
    const currentDate = normalizeAvailabilityDate(selectedAvailabilityDate || fechaInput?.value || '')
    const currentStart = horarioDesde.value || ''
    const currentEnd = horarioHasta.value || ''

    const matchesAvailableSlot = currentDate && currentStart && currentEnd && getAvailabilitySlotsForDate(currentDate).some((slot) => {
        return slot.start === currentStart && slot.end === currentEnd
    })

    const nextSelectedSlot = matchesAvailableSlot
        ? {
            date: currentDate,
            start: currentStart,
            end: currentEnd
        }
        : { date: '', start: '', end: '' }

    const hasChanged =
        nextSelectedSlot.date !== selectedAvailabilitySlot.date ||
        nextSelectedSlot.start !== selectedAvailabilitySlot.start ||
        nextSelectedSlot.end !== selectedAvailabilitySlot.end

    if (hasChanged) {
        selectedAvailabilitySlot = nextSelectedSlot
        renderAvailabilityList(availabilityInlineResult)
    }
}

function applyAvailabilityDateSelection(date) {
    const normalizedDate = normalizeAvailabilityDate(date || '')

    hasUserSelectedBookingDate = true
    selectedAvailabilitySlot = { date: '', start: '', end: '' }
    setSelectedAvailabilityDate(normalizedDate)
    renderAvailabilityList(availabilityInlineResult)
    updateShortNoticeBookingState()
    syncBookingTimeSelects({
        date: normalizedDate
    })
    selectCancha.selectedIndex = 0
    inputMonto.value = '0'
}
function getShortNoticeLimitDate() {
    const limitDate = new Date()
    limitDate.setHours(0, 0, 0, 0)
    limitDate.setDate(limitDate.getDate() + 2)
    return limitDate
}

function getBookingRequestPrefill() {
    if (!bookingRequestPrefillElement) {
        return null
    }

    const requestId = (bookingRequestPrefillElement.dataset.requestId || '').trim()
    if (!requestId) {
        return null
    }

    return {
        requestId,
        requestToken: (bookingRequestPrefillElement.dataset.requestToken || '').trim(),
        type: (bookingRequestPrefillElement.dataset.type || '').trim(),
        date: normalizeDateValue(bookingRequestPrefillElement.dataset.date || ''),
        fieldId: (bookingRequestPrefillElement.dataset.fieldId || '').trim(),
        fieldName: (bookingRequestPrefillElement.dataset.fieldName || '').trim(),
        timeFrom: (bookingRequestPrefillElement.dataset.timeFrom || '').trim(),
        timeUntil: (bookingRequestPrefillElement.dataset.timeUntil || '').trim(),
        visitors: Number(bookingRequestPrefillElement.dataset.visitors || 0),
        minimumVisitors: Number(bookingRequestPrefillElement.dataset.minimumVisitors || 0),
        name: (bookingRequestPrefillElement.dataset.name || '').trim(),
        phone: (bookingRequestPrefillElement.dataset.phone || '').trim(),
        email: (bookingRequestPrefillElement.dataset.email || '').trim(),
        dni: (bookingRequestPrefillElement.dataset.dni || '').trim(),
        city: (bookingRequestPrefillElement.dataset.city || '').trim(),
        typeInstitution: (bookingRequestPrefillElement.dataset.typeInstitution || '').trim(),
    }
}

function setSpecialRequestPrefillLoadingState(isLoading) {
    if (bookingPrefillLoader) {
        bookingPrefillLoader.classList.toggle('d-none', !isLoading)
    }

    if (formBookingContainer) {
        formBookingContainer.classList.toggle('booking-prefill-pending', isLoading)
    }
}

function isConfirmedRequestPrefillActive() {
    if (!specialRequestPrefill?.requestId) {
        return false
    }

    const selectedDate = normalizeDateValue(fechaInput?.value || '')
    if (!selectedDate || selectedDate !== specialRequestPrefill.date) {
        return false
    }

    if (horarioDesde?.value && horarioDesde.value !== specialRequestPrefill.timeFrom) {
        return false
    }

    if (horarioHasta?.value && horarioHasta.value !== specialRequestPrefill.timeUntil) {
        return false
    }

    return true
}


function getSpecialRequestCancelUrl() {
    const requestToken = (specialRequestPrefill?.requestToken || '').trim()

    if (!requestToken) {
        return ''
    }

    return baseUrl + 'cancelarReserva/' + encodeURIComponent(requestToken)
}

function hydrateSpecialRequestActionFromUrl() {
    const params = new URLSearchParams(window.location.search)
    const action = (params.get('specialRequestAction') || '').trim()

    if (!action) {
        return
    }

    const actionMap = {
        cancelled: { message: 'La solicitud especial fue cancelada correctamente.', type: 'success', title: 'Solicitud cancelada' },
        already_cancelled: { message: 'Esta solicitud especial ya estaba cancelada.', type: 'info', title: 'Sin cambios' },
        already_confirmed: { message: 'Esta solicitud especial ya fue confirmada y no puede cancelarse desde este enlace.', type: 'info', title: 'Solicitud confirmada' },
        unavailable: { message: 'La solicitud especial ya no esta disponible.', type: 'error', title: 'No disponible' },
        invalid: { message: 'El enlace de la solicitud especial no es valido.', type: 'error', title: 'Enlace invalido' },
    }

    const selectedAction = actionMap[action] || actionMap.unavailable
    showPublicNotice(selectedAction.message, selectedAction.type, selectedAction.title)

    params.delete('specialRequestAction')
    const queryString = params.toString()
    const nextUrl = window.location.pathname + (queryString ? '?' + queryString : '') + window.location.hash
    window.history.replaceState({}, '', nextUrl)
}

function isShortNoticeBookingSelected() {
    if (isConfirmedRequestPrefillActive()) {
        return false
    }

    const selectedDate = parseInputDate(fechaInput?.value || '')
    if (!selectedDate) {
        return false
    }

    selectedDate.setHours(0, 0, 0, 0)
    return selectedDate < getShortNoticeLimitDate()
}

function updateShortNoticeBookingState() {
    shortNoticeBookingActive = isShortNoticeBookingSelected()
    const shouldShowShortNoticeAlert = shortNoticeBookingActive && hasUserSelectedBookingDate

    if (shortNoticeBookingAlert) {
        shortNoticeBookingAlert.classList.toggle('d-none', !shouldShowShortNoticeAlert)
    }

    if (shortNoticeBookingMessage && shouldShowShortNoticeAlert) {
        const minimumVisitors = Math.max(Number(minVisitantes) || 0, 1)
        shortNoticeBookingMessage.textContent = `Las reservas online requieren una anticipacion minima de 48 horas. Para ${fechaInput?.value || 'esa fecha'}, elegi horario y completa al menos ${minimumVisitors} visitantes para enviar una solicitud especial.`
    }

    availabilityInlineWrapper?.classList.remove('d-none')
    if (shortNoticeBookingActive) {
        bookingTimeRow?.classList.add('d-none')
        divTimeH.style.width = '100%'
        divqtyvisitors.classList.remove('d-none')
        inputqtyvisitors.disabled = false
        applyMinimumVisitorsDefault()
        horarioDesde.value = ''
        horarioHasta.value = ''
        selectCancha.selectedIndex = 0
        divTime.classList.add('d-none')
        horarioHasta.disabled = true
        selectCancha.classList.add('d-none')
        if (!sessionUserLogued) {
            divMonto.classList.remove('d-none')
            inputMonto.value = '0'
        }
    } else if (!horarioDesde.value) {
        bookingTimeRow?.classList.toggle('d-none', !hasUserSelectedBookingDate || !fechaInput?.value)
        divTimeH.style.width = '100%'
        divqtyvisitors.classList.add('d-none')
        inputqtyvisitors.disabled = true
        divTime.classList.add('d-none')
        horarioHasta.disabled = true
        selectCancha.classList.add('d-none')
        if (!sessionUserLogued) {
            divMonto.classList.add('d-none')
        }
    }

    const publicConfirmButton = document.getElementById('confirmarReserva')
    if (publicConfirmButton && !sessionUserLogued) {
        publicConfirmButton.textContent = shortNoticeBookingActive ? 'Solicitar reserva' : 'Confirmar reserva'
    }

    updateBookingStageAvailability()
}

